  'hymn.joyful': { fr: 'Joie au Monde', en: 'Joyful, Joyful', es: 'Alegría, Alegría' },
  'hymn.greatis': { fr: 'Grande Est Ta Fidélité', en: 'Great Is Thy Faithfulness', es: 'Grande Es Tu Fidelidad' },
  'hymn.traditional': { fr: 'Hymne Traditionnel', en: 'Traditional Hymn', es: 'Himno Tradicional' },
  'verse.1cor13': { fr: 'L\'amour est patient, l\'amour est bon. Il n\'envie pas, il ne se vante pas, il ne s\'enfle pas d\'orgueil.', en: 'Love is patient, love is kind. It does not envy, it does not boast, it is not proud.', es: 'El amor es paciente, es bondadoso. El amor no es envidioso ni jactancioso ni orgulloso.' },
  'verse.1cor13.full': { fr: 'L\'amour est patient, l\'amour est bon. Il ne jalouse pas, il ne se vante pas, il ne s\'enfle pas d\'orgueil. Il ne fait rien de malhonnête, il ne cherche pas son intérêt. Il supporte tout, il croit tout, il espère tout, il endure tout.', en: 'Love is patient, love is kind. It does not envy, it does not boast, it is not proud. It does not dishonor others, it is not self-seeking. It always protects, always trusts, always hopes, always perseveres.', es: 'El amor es paciente, es bondadoso. No es envidioso ni jactancioso ni orgulloso. No deshonra a los demás, no es egoísta. Todo lo protege, todo lo cree, todo lo espera, todo lo soporta.' },
  'verse.genesis': { fr: 'C\'est pourquoi l\'homme quittera son père et sa mère, et s\'attachera à sa femme, et ils deviendront une seule chair.', en: 'Therefore a man shall leave his father and his mother and hold fast to his wife, and they shall become one flesh.', es: 'Por eso el hombre dejará a su padre y a su madre, y se unirá a su esposa, y serán una sola carne.' },
  'verse.ecclesiastes': { fr: 'Deux valent mieux qu\'un seul, car ils ont un bon salaire de leur travail. Car s\'ils tombent, l\'un relève son compagnon.', en: 'Two are better than one, because they have a good reward for their toil. For if they fall, one will lift up his fellow.', es: 'Más valen dos que uno solo, porque obtienen más fruto de su esfuerzo. Si caen, el uno levanta al otro.' },
  'verse.proverbs': { fr: 'Confie-toi en l\'Éternel de tout ton cœur, et ne t\'appuie pas sur ta propre intelligence. Reconnais-le dans toutes tes voies, et il aplanira tes sentiers.', en: 'Trust in the Lord with all your heart, and do not lean on your own understanding. In all your ways acknowledge him, and he will make straight your paths.', es: 'Confía en el Señor con todo tu corazón, y no te apoyes en tu propia prudencia. Reconócelo en todos tus caminos, y él enderezará tus sendas.' },
  'verse.colossians': { fr: 'Et par-dessus tout, revêtez-vous de l\'amour, qui est le lien de la perfection.', en: 'And above all these put on love, which binds everything together in perfect harmony.', es: 'Y sobre todas estas cosas, vestíos de amor, que es el vínculo de la perfección.' },
  'verse.romans12': { fr: 'Soyez pleins d\'affection les uns pour les autres dans l\'amour fraternel; rendez-vous honneur les uns aux autres.', en: 'Be devoted to one another in love. Honor one another above yourselves.', es: 'Amaos los unos a los otros con amor fraternal, dándoos preferencia los unos a los otros.' },
  'verse.galatians': { fr: 'Mais le fruit de l\'Esprit, c\'est l\'amour, la joie, la paix, la patience, la bonté, la bienveillance, la fidélité, la douceur, la maîtrise de soi.', en: 'But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faithfulness, gentleness, self-control.', es: 'Pero el fruto del Espíritu es amor, alegría, paz, paciencia, amabilidad, bondad, fidelidad, mansedumbre, dominio propio.' },
  'verse.psalm37': { fr: 'Fais de l\'Éternel tes délices, et il te donnera ce que ton cœur désire.', en: 'Delight yourself in the Lord, and he will give you the desires of your heart.', es: 'Deléitate en el Señor, y él te dará las peticiones de tu corazón.' },
