  'qr.title': { fr: 'Notre Code Personnel', en: 'Our Personal Code', es: 'Nuestro Código Personal' },
  'qr.desc': { fr: 'Scannez ce code pour accéder rapidement à notre page de mariage ou partagez-le avec vos proches.', en: 'Scan this code for quick access to our wedding page or share it with your loved ones.', es: 'Escanea este código para acceder rápidamente a nuestra página de boda o compártelo con tus seres queridos.' },
  'qr.placeholder': { fr: 'QR Code', en: 'QR Code', es: 'Código QR' },
  'qr.hint': { fr: 'Partagez l\'amour, envoyez ce lien à votre famille et vos amis', en: 'Share the love, send this link to your family and friends', es: 'Comparte el amor, envía este enlace a tu familia y amigos' },
  'court.title': { fr: 'Nos Citations Personnelles', en: 'Our Personal Quotes', es: 'Nuestras Citas Personales' },
  'court.desc': { fr: 'Ce en quoi nous croyons, nos valeurs et les principes qui guident notre union.', en: 'What we believe in, our values, and the principles that guide our union.', es: 'En lo que creemos, nuestros valores y los principios que guían nuestra unión.' },
  'court.belief.love': { fr: 'L\'Amour Inconditionnel', en: 'Unconditional Love', es: 'Amor Incondicional' },
  'court.belief.love.desc': { fr: 'Nous croyons que l\'amour véritable est patient, bienveillant et ne cherche pas son propre intérêt. C\'est le fondement de tout ce que nous construisons ensemble.', en: 'We believe that true love is patient, kind, and does not seek its own interest. It is the foundation of everything we build together.', es: 'Creemos que el amor verdadero es paciente, bondadoso y no busca lo suyo. Es el fundamento de todo lo que construimos juntos.' },
  'court.belief.faith': { fr: 'La Foi Inébranlable', en: 'Unwavering Faith', es: 'Fe Inquebrantable' },
  'court.belief.faith.desc': { fr: 'Notre foi en Dieu est notre ancre. Nous Lui faisons confiance pour guider nos pas et bénir notre chemin ensemble.', en: 'Our faith in God is our anchor. We trust Him to guide our steps and bless our journey together.', es: 'Nuestra fe en Dios es nuestra ancla. Confiamos en Él para guiar nuestros pasos y bendecir nuestro camino juntos.' },
  'court.belief.family': { fr: 'La Famille Unie', en: 'United Family', es: 'Familia Unida' },
  'court.belief.family.desc': { fr: 'Nous valorisons la famille comme un don sacré. Ensemble, nous bâtissons un foyer rempli de joie, de respect et de soutien mutuel.', en: 'We value family as a sacred gift. Together, we build a home filled with joy, respect, and mutual support.', es: 'Valoramos la familia como un don sagrado. Juntos, construimos un hogar lleno de alegría, respeto y apoyo mutuo.' },
  'court.belief.grace': { fr: 'La Grâce & la Gratitude', en: 'Grace & Gratitude', es: 'Gracia y Gratitud' },
  'court.belief.grace.desc': { fr: 'Nous vivons avec grâce et gratitude, reconnaissant chaque bénédiction et choisissant la bonté dans chaque moment.', en: 'We live with grace and gratitude, acknowledging every blessing and choosing kindness in every moment.', es: 'Vivimos con gracia y gratitud, reconociendo cada bendición y eligiendo la bondad en cada momento.' },
  'index.foundedOnFaith': { fr: 'Fondé sur la Foi', en: 'Founded on Faith', es: 'Fundado en la Fe' },
  'index.ceremony': { fr: 'Cérémonie Sacrée', en: 'Sacred Ceremony', es: 'Ceremonia Sagrada' },
  'index.ceremony.desc': { fr: 'Une célébration d\'amour devant Dieu, notre famille et nos amis les plus chers.', en: 'A celebration of love before God, our family, and our dearest friends.', es: 'Una celebración de amor ante Dios, nuestra familia y nuestros amigos más queridos.' },
  'index.blessing': { fr: 'Bénédiction Divine', en: 'Divine Blessing', es: 'Bendición Divina' },
  'index.blessing.desc': { fr: 'Recevant la grâce et la bénédiction de Dieu sur notre union sacrée.', en: 'Receiving God\'s grace and blessing upon our sacred union.', es: 'Recibiendo la gracia y bendición de Dios sobre nuestra unión sagrada.' },
  'index.vows': { fr: 'Vœux Éternels', en: 'Eternal Vows', es: 'Votos Eternos' },
  'index.vows.desc': { fr: 'Des promesses faites devant Dieu, scellées par la foi et l\'amour éternel.', en: 'Promises made before God, sealed by faith and eternal love.', es: 'Promesas hechas ante Dios, selladas por la fe y el amor eterno.' },
  'index.fellowship': { fr: 'Communion Fraternelle', en: 'Fellowship & Joy', es: 'Comunión y Alegría' },
  'index.fellowship.desc': { fr: 'Célébrer ensemble dans la joie, la prière et la reconnaissance.', en: 'Celebrating together in joy, prayer, and gratitude.', es: 'Celebrando juntos con alegría, oración y gratitud.' },

